import { NextResponse } from "next/server";
import { db } from "@/lib/db";
import bcrypt from "bcryptjs";
import path from "path";
import fs from "fs/promises";
import nodemailer from "nodemailer";
import pdf from "pdf-parse";
import OpenAI from "openai";

const openai = new OpenAI({ apiKey: process.env.OPENAI_API_KEY });

const generateOTP = () => Math.floor(1000 + Math.random() * 9000).toString();

export const config = {
  api: {
    bodyParser: {
      sizeLimit: "10mb",
    },
  },
};

const uploadDir = path.join(process.cwd(), "public/uploads");
fs.mkdir(uploadDir, { recursive: true }).catch(console.error);

const saveFile = async (file: File) => {
  const fileName = `${Date.now()}-${file.name.replace(/\s+/g, "_")}`;
  const filePath = path.join(uploadDir, fileName);

  const buffer = Buffer.from(await file.arrayBuffer());
  await fs.writeFile(filePath, buffer);
  return `/uploads/${fileName}`;
};

const transporter = nodemailer.createTransport({
  host: process.env.EMAIL_HOST,
  port: Number(process.env.EMAIL_PORT),
  secure: process.env.EMAIL_PORT === "465",
  auth: {
    user: process.env.EMAIL_USER,
    pass: process.env.EMAIL_PASS,
  },
});

async function extractTextFromPDF(filePath: string): Promise<string> {
  try {
    const dataBuffer = await fs.readFile(filePath);
    const data = await pdf(dataBuffer);
    return data.text;
  } catch (error) {
    console.error("Error reading PDF:", error);
    return "";
  }
}

async function analyzeTextWithOpenAI(text: string): Promise<boolean> {
  const prompt = `
    Given the extracted text from a document, determine if it is a valid 10th or 12th marksheet. 
    A valid marksheet must contain:
    - Student's Name
    - Subjects and corresponding Marks
    - Total Marks or Percentage

    If the document contains these, respond with "valid". Otherwise, respond with "invalid".
    
    Text:
    ${text}
  `;

  const response = await openai.completions.create({
    model: "gpt-4",
    prompt,
    max_tokens: 10,
  });

  console.log("Open Ai response", response);
  

  return response.choices[0].text.trim().toLowerCase() === "valid";
}

export async function POST(req: Request) {
  try {
    const formData = await req.formData();

    const name = formData.get("name") as string;
    const email = formData.get("email") as string;
    const password = formData.get("password") as string;
    const phone_number = formData.get("phone_number") as string;
    const country_id = Number(formData.get("country_id"));
    const program_id = Number(formData.get("program_id"));
    const university_id = Number(formData.get("university_id"));
    const id_proof = formData.get("id_proof") as string;

    if (!id_proof) {
      return NextResponse.json(
        { error: "id_proof is required" },
        { status: 400 }
      );
    }

    const requiredFiles = ["tenth_certificate", "twelfth_certificate"];
    const filePaths: { [key: string]: string } = {};

    for (const fileKey of requiredFiles) {
      const file = formData.get(fileKey) as File;
      if (!file) {
        return NextResponse.json(
          { error: `${fileKey} is required` },
          { status: 400 }
        );
      }
      if (!file.name.toLowerCase().endsWith(".pdf")) {
        return NextResponse.json(
          { error: `${fileKey} must be a PDF` },
          { status: 400 }
        );
      }

      const filePath = await saveFile(file);
      filePaths[fileKey] = filePath;

      // Extract text and validate marksheet
      const extractedText = await extractTextFromPDF(
        path.join(process.cwd(), "public", filePath)
      );
      const isValid = await analyzeTextWithOpenAI(extractedText);
      if (!isValid) {
        return NextResponse.json(
          { error: `${fileKey} is not a valid marksheet` },
          { status: 400 }
        );
      }
    }

    let paths: string[] = [];
    for (let i = 0; ; i++) {
      const file = formData.get(`other_certificate[${i}]`) as File | null;
      if (!file) break;
      const filePath = await saveFile(file);
      paths.push(filePath);
    }
    const otherPaths = paths.length > 0 ? paths.join(" ") : null;

    const hashedPassword = await bcrypt.hash(password, 10);

    const otp = generateOTP();
    const otpExpiry = new Date(Date.now() + 10 * 60 * 1000);

    await db.query(
      `INSERT INTO users (name, email, password, phone_number, country_id, program_id, university_id, id_proof, otp, otp_expires_at, tenth_certificate, twelfth_certificate, other_certificate) 
     VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?);`,
      [
        name,
        email,
        hashedPassword,
        phone_number,
        country_id,
        program_id,
        university_id,
        id_proof,
        otp,
        otpExpiry,
        filePaths.tenth_certificate,
        filePaths.twelfth_certificate,
        otherPaths,
      ]
    );

    try {
      await transporter.sendMail({
        from: process.env.EMAIL_USER,
        to: email,
        subject: "Your OTP for Registration",
        html: `
          <p>Dear <strong>${name}</strong>,</p>
          <p>Your OTP for registration is: <strong>${otp}</strong></p>
          <p>This OTP is valid for 10 minutes.</p>
          <p>Best Regards,<br><strong>BringUrBuddy Team</strong></p>
        `,
      });
    } catch (emailError) {
      console.error("Email Sending Error:", emailError);
      return NextResponse.json(
        { error: "User registered but failed to send OTP email." },
        { status: 500 }
      );
    }

    return NextResponse.json({ message: "success" }, { status: 201 });
  } catch (error) {
    console.error("Registration Error:", error);
    return NextResponse.json(
      { error: "Internal Server Error" },
      { status: 500 }
    );
  }
}
